import { jsPDF } from "jspdf";
var font =
  "";

var callAddFont = function () {
  this.addFileToVFS("ProximaNova-RegularIt-normal.ttf", font);
  this.addFont(
    "ProximaNova-RegularIt-normal.ttf",
    "ProximaNova-RegularIt",
    "normal"
  );
};

jsPDF.API.events.push(["addFonts", callAddFont]);
